// Get the incoming form data from the first input item
const formData = items[0].json.body;

// Get the program name from the form and convert it to lowercase for easy matching
const program = formData.program.toLowerCase();

// Set a default department if no match is found
let department = 'Other'; 

// --- Logic to determine the department based on your full program list ---

// 1. Engineering & Technology
if (program.includes('diploma in engineering') || program.includes('b.tech') || program.includes('m.tech')) {
  department = 'Engineering & Technology';
} 
// 2. Pharmacy & Allied Health
else if (program.includes('b.pharm') || program.includes('m.pharm') || program.includes('bams') || program.includes('bhms')) {
  department = 'Pharmacy & Allied Health';
} 
// 3. Nursing
else if (program.includes('anm') || program.includes('gnm') || program.includes('b.sc. nursing') || program.includes('p.b.b.sc. nursing')) {
  department = 'Nursing';
}
// 4. Science & Comp. Apps.
else if (program.includes('b.sc.') || program.includes('bca') || program.includes('m.sc.') || program.includes('mca') || program.includes('imca') || program.includes('dmlt')) {
  department = 'Science & Comp. Apps.';
}
// 5. Management & Commerce
else if (program.includes('bba') || program.includes('b.com') || program.includes('mba') || program.includes('m.com') || program.includes('imba') || program.includes('bms')) {
  department = 'Management & Commerce';
}
// 6. Arts & Education
else if (program.includes('b.a.') || program.includes('b.ed')) {
  department = 'Arts & Education';
}
// 7. Library Science
else if (program.includes('b.lib.i.sc.') || program.includes('m.lib.i.sc.')) {
  department = 'Library Science';
}
// 8. Vocational Studies
else if (program.includes('b.voc') || program.includes('m.voc')) {
  department = 'Vocational Studies';
}
// 9. Doctoral Studies (for Ph.D.)
else if (program.includes('ph.d.')) {
  department = 'Doctoral Studies';
}

// Add the new, clean 'department' field to the data
formData.department = department;

// Return all the original data, plus our new field, for the next node to use
return items;

